var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 소대장, 선배는 괜찮을까?","JPN":" 小隊長、先輩は大丈夫かな？","ENG":"Commander, will Shiyoon be okay?","TWN":"小隊長，前輩沒事吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 녀석이 자진해서 나선 일이다. 믿는 구석이 있다는 뜻이겠지.","JPN":" 奴が自分からやるって言ったんだ。何か自信があるんだろう。","ENG":"He put himself up to it. He must have his ace up his sleeve.","TWN":"這件事是他自告奮勇說要去的，就表示他心裡應該有譜吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 하지만 갑자기 그 황태자를 이길 수 있다고 큰소리 쳐도……. 믿기 어렵잖아.","JPN":" でもいきなりあの皇太子に勝てるって豪語されても……信じられるわけないじゃない。","ENG":"But even if he thinks that he can win over the prince, all of a sudden... It's hard to believe.","TWN":"但是突然誇下海口說能贏過那個皇太子……的確很難讓人相信啊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 신입에게 그런 걱정도 받고, 못난 제자 녀석이 신세가 많이 폈군.","JPN":" 新人にそんな心配までされて、出来の悪い弟子がかなり世話をかけたようだな。","ENG":"My poor apprentice must be quite a burden, seeing that a rookie is worried over him.","TWN":"還要新人為他擔心，我這沒出息的徒弟到底是有多累贅啊。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 다른 사람보단 너 자신부터 먼저 챙겨라.","JPN":" 他人よりまずは自分の心配をしろ。","ENG":"Take care of yourself foremost, before you care for anyone else.","TWN":"比起別人，你還是先顧好你自己吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 어정쩡한 자세로 네헤모트와 맞부딪쳤다간 필패일 테니까.","JPN":" 生半可な姿勢でネヘモトとやり合っても勝ち目はないからな。","ENG":"It's given that you will lose against Nehemoth with insufficient determination.","TWN":"沒有覺悟就對上貝赫莫特，你必敗無疑。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 작전은 잊지 않았겠지?","JPN":" 作戦は忘れてないな？","ENG":"I assume you haven't forgotten our plan, no?","TWN":"作戰計畫還沒忘記吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 소대장이 네헤모트를 요격하고, 그 사이 통로를 파괴한다. 맞지?","JPN":" 小隊長がネヘモトを迎撃して、その間に通路を破壊する。でしょ？","ENG":"While you fire at Nehemoth, I destroy the tunnel. Am I right?","TWN":"在小隊長攔截貝赫莫特的時候，我利用那個空檔破壞通道，對吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 그런데 정말 혼자 괜찮겠어?","JPN":" でも本当に一人で大丈夫なの？","ENG":"Are you sure about this, though?","TWN":"不過你一個人真的沒問題嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 한 번.","JPN":" 一度だけ。","ENG":"One chance.","TWN":"一次。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 선공이라는 가정 하에, 한 번은 기회를 만들어 줄 수 있다.","JPN":" 先制攻撃という前提で、一度だけチャンスは作ってやれる。","ENG":"Under the condition that we attack first, I can give you one chance.","TWN":"在我們搶先攻擊的情況下，可以創造一次機會。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 그 이후는 드래곤 버스터가 버텨 주느냐의 문제겠지.","JPN":" そのあとは、ドラゴンバスターが耐えられるかの問題だ。","ENG":"After that, it'll be up to the Dragon Buster to last long enough.","TWN":"那之後就是要看屠龍者還能否撐得下去了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 통로를 파괴하면 네헤모트는 어떻게 되는 거야?","JPN":" 通路を破壊したらネヘモトはどうなるの？","ENG":"What happens to Nehemoth if we succeed in destroying the tunnel?","TWN":"破壞通道後，貝赫莫特會怎麼樣？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 통로가 재건될 때까지는 얌전히 지내겠지.","JPN":" 通路が再建されるまでは、大人しくしているしかないだろうな。","ENG":"He will lie low until the tunnel gets rebuilt.","TWN":"在通道重建之前，應該都會乖乖待著吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 하지만 쓸데없는 기대는 하지 마라.","JPN":" しかし無意味な期待はやめろ。","ENG":"But don't get your hopes up.","TWN":"不過別做無謂的期待。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 동료들도 잃고, 본색까지 드러낸 풋내기 마왕과 예전처럼 지낼 가능성은 없으니까.","JPN":" 仲間を失い、本性まで表した青二才の魔王と、以前のように仲良くできるなんてことはないからな。","ENG":"Things won't be the same, seeing that he lost all of his comrades and revealed his true identity.","TWN":"失去同伴，露出本來面目的新手魔王，你和他應該無法再像以前那樣相處了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 그렇겠지. 나도 알고 있어.","JPN":" そうだね。わかってる。","ENG":"Maybe so. I know.","TWN":"應該是吧……我心裡也有數。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 하지만 소대장, 내가 만약에…….","JPN":" でも小隊長、もし私が……","ENG":"But Commander, what if I...","TWN":"但是小隊長，如果我……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 음?","JPN":" ん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 클리포트 게임 같은, 어처구니없는 짓을 하게 만든 녀석을 박살내 버리면.","JPN":" クリフォトゲームのような、意味のわからないことをやらせた奴を倒しちゃったら。","ENG":"What if I destroy the moron who made the Qliphoth Game take place?","TWN":"如果我把制定出逆卡巴拉遊戲這種荒謬遊戲的傢伙教訓一番。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 그 때는…… 레이 선배도 뭔가 달라지지 않을까?","JPN":" その時には……レイ先輩も何か変わるんじゃないかな？","ENG":"If that happens... Will Ray be different?","TWN":"到時候……雷伊前輩也會有什麼改變吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 모르는 게 약이란 말이 너만큼 잘 어울리는 녀석도 없을 거다.","JPN":" お前ほど知らぬが仏という言葉が似合う奴もいないだろう。","ENG":"The best advice I could give to you is that sometimes it's better to not know.","TWN":"無知便是福，這句話再適合你不過了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 글쎄요. 무지는 죄라고 생각하는데요, 스승님.","JPN":" そうですかね。私は無知は罪だと思いますよ、師匠。","ENG":"Well, Master. I consider ignorance a sin.","TWN":"這個嘛，我認為無知是罪，師父。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 하물며 그 당사자가 <color=#ffd34c>늑대</color>라면 더더욱 말이죠.","JPN":" ましてやその当事者が<color=#ffd34c>狼</color>となれば、なおさらね。","ENG":"Especially if the subject is <color=#ffd34c>the Wolf</color>.","TWN":"如果那個當事人是<color=#ffd34c>狼</color>的話就更是了。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 저 사람은…… 선배가 붙잡혔을 때 나타났던…….","JPN":" あの人は……先輩が捕まっていたときに現れた……","ENG":"That person... he appeared when Shiyoon was caught...","TWN":"你是……前輩被抓走的時候出現的……"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 여기 틀어박혀 있었군, 나유빈.","JPN":" ここに隠れていたのか、イチノセ。","ENG":"So there you are, Na Yubin.","TWN":"你原來躲在這裡，羅瑜斌。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 지금은 네 불평을 들어 줄 시간 없다. 물러서.","JPN":" 今お前の愚痴を聞いてやれる時間はない。下がれ。","ENG":"I don't have time to listen to your complaints. Stand back.","TWN":"我現在沒時間聽你抱怨，讓開。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 화기애애한 시간을 방해했다면 죄송합니다.","JPN":" 和気あいあいな時間を邪魔して申し訳ありません。","ENG":"I'm sorry if I interrupted your happy hour.","TWN":"如果打擾了你們的溫馨時光，那我很抱歉。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 하지만 저도 원만한 사회 생활을 위해서라면 해야 할 일이 있어서요.","JPN":" でも私にも円満な社会生活のためにやらなければならないことがあるんです。","ENG":"But I have things to do, in order to maintain mine.","TWN":"不過為了保證今後生活順利，我也有我自己要做的事。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 파트너십을 유지하기 위한 최소한의 호의라고 할까요.","JPN":" パートナーシップを維持するための最低限の好意とでも言いますか。","ENG":"It's the least I could do to maintain my partnership.","TWN":"該說是維持合夥關係最起碼的善意嗎？"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 그래. 애초에 비킬 마음이 있었다면 낯짝을 내밀지도 않았겠지.","JPN":" そうだな。退く気があるなら最初から現れもしなかっただろう。","ENG":"Yes. You wouldn't have shown your face if you had the intention to stand back.","TWN":"也對。照你的個性，如果一開始就想讓開，你就不會露面了。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 신입. 우리가 여기 온 목적에 집중해라.","JPN":" 新人。私たちがここにいる目的に集中しろ。","ENG":"Rookie. Focus on our objective.","TWN":"新人，專注於我們來這裡的目的。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":" 저기 보이는 왕좌를 부수면 우리의 승리다. 그 외에 다른 건 모두 잊도록.","JPN":" あそこに見える王座をぶち壊せば私たちの勝利だ。それ以外のことはすべて忘れろ。","ENG":"Our victory is achieved only by breaking the throne over there. Don't forget that.","TWN":"破壞那邊的寶座我們就贏了。除此之外，不要多管。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" ……알겠어, 소대장.","JPN":" ……わかった、小隊長。","ENG":"...Got it, Commander.","TWN":"……知道了，小隊長。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 직접 부딪치는 건 처음이었던가요, 유미나 양.","JPN":" 僕と直接やり合うのは初めてですよね、ミナさん。","ENG":"Is it your first time clashing with me, Mina?","TWN":"這還是我們二個第一次直接碰面吧，劉米娜？"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 그럼 어디, 스승님의 기대에 부응하실 수 있을지……. ","JPN":" では、師匠の期待に応えられるかどうか…… ","ENG":"Well, then. Let's see if you can live up to Master's expectations...","TWN":"那就讓我這個前輩來看看……"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":" 선배로서 확인해 봐야겠네요.","JPN":" 先輩として確かめないといけませんね。","ENG":"Because I need to check, as your predecessor.","TWN":"你能否對得起師父的期待吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};